import React, { useState, useContext, useEffect } from 'react';
import { Button, Segment, Form, Divider, Header} from 'semantic-ui-react';
import { StoreContext } from './StoreContext';

const Admin = () => {
  const {web3, contract, accounts} = useContext(StoreContext);
  const [paused, setPaused] = useState(false);
  const [newOwnerAddress, setNewOwnerAddress] = useState("");

  useEffect(() => {
    const init = async () => {
      const res = await contract.methods.paused().call();
      setPaused(res);
    };
    init();
  }, []);

  const handelPaused = async (e) => {
    if(!paused) {
      await contract.methods
      .pause()
      .send({ from: accounts[0] })
      .on('receipt', () => {
        window.location.href = "/admin";
      })
      .on('confirmation', () => {
        window.location.href = "/admin";
      });
    } else {
      await contract.methods
      .unPause()
      .send({ from: accounts[0] })
      .on('receipt', () => {
        window.location.href = "/admin";
      })
      .on('confirmation', () => {
        window.location.href = "/admin";
      });
    }
  }

  const handelSubmit = async e => {
    e.preventDefault();
    console.log(newOwnerAddress);
    await contract.methods
    .transferContractOwnership(newOwnerAddress)
    .send({ from: accounts[0] })
    .on('receipt', () => {
      window.location.href = "/admin";
    })
    .on('confirmation', () => {
      window.location.href = "/admin";
    });
  }

  return (
    <div>
      <Segment inverted color={paused ? 'orange' : 'olive'}>
        Contract is <b>{paused ? 'paused' : 'unpaused'}</b>
      </Segment>
      <Button onClick={handelPaused}>{paused ? 'Unpause' : 'Pause'}</Button>
      {/*
      <Segment>
        <Header as='h2' floated='right'>
          Transfer Ownership
        </Header>
        <Divider clearing />
        <Form onSubmit={handelSubmit}>
          <Form.Field>
            <label>New Owner Address</label>
            <input
              type="text"
              value={newOwnerAddress}
              onChange={e => setNewOwnerAddress(e.target.value)}
            />
          </Form.Field>
          <Button type='submit'>Submit</Button>
        </Form>
      </Segment>
      */}
    </div>
  )
}

export default Admin;
